select u.USER_ID, u.USERNAME, u.PASSWORD, u.LAST_LOGIN, u.NAME, u.IP, u.END_TIME, u.YEARS, u.STATUS, u.EMAIL, u.PHONE, u.SEX, u.SFID, u.NUMBER, u.PARENT_ID, r.ROLE_ID, r.ROLE_NAME, u.ADDRESS from
u,
r where u.ROLE_ID = r.ROLE_ID and r.PARENT_ID = '2'
and ( u.USERNAME LIKE CONCAT(CONCAT('%', #{keywords}),'%') or u.EMAIL LIKE CONCAT(CONCAT('%', #{keywords}),'%') or u.NUMBER LIKE CONCAT(CONCAT('%', #{keywords}),'%') )
