select u.USER_ID, u.USERNAME, u.PASSWORD, u.LAST_LOGIN, u.NAME, u.IP, u.END_TIME, u.YEARS, u.STATUS, u.EMAIL, u.PHONE, u.SEX, u.NUMBER, u.PARENT_ID, u.ADDRESS, r.ROLE_ID, r.ROLE_NAME, ifnull((select sum(o.ORDER_TOTAL) from SHOP_ORDER o where o.USER_ID in (select USER_ID from SYS_APP_USER where INNER_CODE like concat(u.INNER_CODE,'%') and INNER_CODE != u.INNER_CODE) and o.status in (1,2,5,6)),0) as ORDER_TOTAL, ifnull((((select sum(o.ORDER_TOTAL) from SHOP_ORDER o where o.USER_ID in (select USER_ID from SYS_APP_USER where INNER_CODE like concat(u.INNER_CODE,'%') and INNER_CODE != u.INNER_CODE) and o.status in (1,2,5,6)))*(select n.COMMISION_RATIO from SHOP_COMMISION n where n.COMMISION_SORT=(ifnull(LENGTH(u.INNER_CODE),0)/32)))/10000,0) as COMMISION_TOTAL from
u,
r where u.ROLE_ID = r.ROLE_ID and r.PARENT_ID = '2'
and ( u.USERNAME LIKE CONCAT(CONCAT('%', #{pd.keywords}),'%') or u.EMAIL LIKE CONCAT(CONCAT('%', #{pd.keywords}),'%') or u.NUMBER LIKE CONCAT(CONCAT('%', #{pd.keywords}),'%') )
and u.ROLE_ID=#{pd.ROLE_ID}
and u.END_TIME >= #{pd.lastLoginStart}
and u.END_TIME <= #{pd.lastLoginEnd}
and u.STATUS=#{pd.STATUS}
and u.PARENT_ID=#{pd.USER_ID}
order by u.NAME
